            // 2026-07-18: 허니콤 테이블(hb_tb_*) — 매대와 같은 입력/첨부를 쓰되 프롬프트만 테이블용
            if (typeof _soIsTableProduct === 'function' && _soIsTableProduct(state.product)) return 'hb-table';
