    // 2026-06-13: SHEET 시스템 통합 — VINYL_CODES_ORDERED 에 흡수됨. 별도 SHEET 섹션은 노출 안 함.
    var SHEET_CODES_ORDERED = [];
    function _soIsSheetProduct(p) {
        return false;  // SHEET 섹션 비활성 — vinyl 6종 그리드에서 통합 처리
    }
    var _soSheetCache = null;
    async function _soLoadSheetVariants(currentCode) {
        var sec = document.getElementById('soSheetVariantsSec');
        var grid = document.getElementById('soSheetVariants');
        if (!sec || !grid) return;
        try {
            if (!_soSheetCache) {
                var sb = getSb(); if (!sb) { sec.style.display = 'none'; return; }
                var _COLS = 'code,name,name_jp,name_us,price,price_jp,price_us,img_url,category,sort_order,width_mm,height_mm';
                var r1 = await sb.from('admin_products').select(_COLS).in('code', SHEET_CODES_ORDERED);
                var rows = (r1 && r1.data) || [];
                var _byCode = {};
                rows.forEach(function(r){ if (r && r.code) _byCode[r.code] = r; });
                _soSheetCache = SHEET_CODES_ORDERED
                    .map(function(c){ return _byCode[c]; })
                    .filter(function(r){ return !!r; });
                console.log('[so] sheet variants loaded:', _soSheetCache.length);
            }
            if (_soSheetCache.length < 2) { sec.style.display = 'none'; return; }
            var lang = window.__PS_LANG || (window.__SITE_CODE === 'JP' ? 'ja' : window.__SITE_CODE === 'US' ? 'en' : 'ko');
            grid.innerHTML = _soSheetCache.map(function (p) {
                var nm = p.name; if (lang === 'ja' && p.name_jp) nm = p.name_jp; else if (lang !== 'ko' && p.name_us) nm = p.name_us;
                var img = p.img_url || 'https://placehold.co/200?text=Sheet';
                var safeNm = String(nm || '').replace(/[<>"]/g, '');
                var safeCode = String(p.code || '').replace(/'/g, "\\'");
                var priceVal = p.price || 0;
                var isCur = (p.code === currentCode);
                var borderColor = isCur ? '#7c3aed' : '#e7e5e4';
                var borderW = isCur ? '2.5px' : '1.5px';
                var ring = isCur ? 'box-shadow:0 0 0 3px rgba(124,58,237,0.15);' : '';
                return '<div onclick="window._soSwitchSheet(\'' + safeCode + '\')" style="cursor:pointer; display:flex; flex-direction:column; border:' + borderW + ' solid ' + borderColor + '; border-radius:10px; overflow:hidden; background:#fff; transition:border-color .15s ease; ' + ring + '">' +
                    '<div style="position:relative; padding-bottom:100%; background:#f8fafc; overflow:hidden;">' +
                        '<img src="' + img + '" loading="lazy" style="position:absolute; inset:0; width:100%; height:100%; object-fit:cover;" onerror="this.style.opacity=0">' +
                        (isCur ? '<div style="position:absolute; top:4px; right:4px; background:#7c3aed; color:#fff; padding:2px 6px; border-radius:4px; font-size:9.5px; font-weight:900;">' + tr('현재','現在','Current') + '</div>' : '') +
                    '</div>' +
                    '<div style="padding:6px 8px;">' +
                        '<div style="font-size:11px; font-weight:700; color:#1e293b; line-height:1.3; height:28px; overflow:hidden;" title="' + safeNm + '">' + safeNm + '</div>' +
                        '<div style="font-size:11px; font-weight:800; color:#dc2626; margin-top:2px;">' + fmtPrice(priceVal) + '</div>' +
                    '</div>' +
                '</div>';
            }).join('');
            sec.style.display = '';
        } catch (e) { console.warn('[so] sheetVariants render', e); sec.style.display = 'none'; }
    }
    window._soLoadSheetVariants = _soLoadSheetVariants;
    window._soIsSheetProduct = _soIsSheetProduct;

    window._soSwitchSheet = function (code) {
        if (!code) return;
        try {
            if (typeof window.openSimpleOrderModal === 'function') {
                window.openSimpleOrderModal(code);
            } else {
                location.href = location.pathname + '?product=' + encodeURIComponent(code);
            }
        } catch (e) { console.warn('[so] switchSheet', e); }
    };

    // 2026-06-13: 낱장 인쇄 (pp_lf_*) — A4/A3/A2 사이즈 × 단면/양면 정찰가 (1매 기준 perSheet) + 수량별 할인.
    //   비규격 사이즈는 가로/세로 입력 → 가장 작은 표준 사이즈로 자동 매핑.
    //   용지/박/후가공은 명함 (BIZ_PAPERS/BIZ_FOILS/BIZ_FINISHES) 재사용.
    // 2026-06-14: per-sheet 가격 + 단순 3-tier 할인으로 재작성.
    //   A4=500원/매, A3=1000원/매, A2=2000원/매. 양면=단면×1.5.
    //   100매+ 20% / 500매+ 30% / 1000매+ 50%.
    //   박/후가공 옵션은 (100매+ ×2 / 500매+ ×3 / 1000매+ ×4) multiplier.
    // 2026-06-14: 양면 = 단면 × 1.2 (사용자 지정: A4 양면 600원).
    var LEAFLET_SIZES = [
        { id:'A4', label:'A4', wMm:210, hMm:297, perSheet: { single: 500,  double: 600  } },
        { id:'A3', label:'A3', wMm:297, hMm:420, perSheet: { single: 1000, double: 1200 } },
        { id:'A2', label:'A2', wMm:420, hMm:594, perSheet: { single: 2000, double: 2400 } }
    ];
    function _soLeafletQtyDisc(qty) {
        // 2026-07-02: 리플렛(낱장) 수량 볼륨 할인 재도입 — 일본(kingprinters) 대량가보다 저렴하게.
        //   예) A3 양면 1,000장 = 1,200×1000×0.16 = 192,000원 = ¥19,200 (kingprinters 折パンフ ¥20,493 대비 ↓).
        //   소량(1~99)은 정가 유지(1장부터 소량 특화). 100장↑부터 대량할인.
        qty = Math.max(1, parseInt(qty, 10) || 1);
        if (qty >= 3000) return 0.12;
        if (qty >= 1000) return 0.16;
        if (qty >= 500)  return 0.24;
        if (qty >= 300)  return 0.34;
        if (qty >= 100)  return 0.50;
        return 1.00;
    }
    // 박/후가공 옵션 multiplier — 수량 구간별로 base option price 배수
    function _soLeafletOptMult(qty) {
        if (qty >= 1000) return 4;
        if (qty >= 500)  return 3;
        if (qty >= 100)  return 2;
        return 1;
    }
    // 입력 사이즈 → 가장 작은 표준 사이즈로 매핑 (A4 ≤ A3 ≤ A2)
    function _soLeafletAutoSize(wMm, hMm) {
        var w = Math.max(parseInt(wMm, 10) || 0, parseInt(hMm, 10) || 0);
        var h = Math.min(parseInt(wMm, 10) || 0, parseInt(hMm, 10) || 0);
        // longer side: A4=297 / A3=420 / A2=594
        if (w <= 297 && h <= 210) return 'A4';
        if (w <= 420 && h <= 297) return 'A3';
        return 'A2';
    }
    function _soLeafletPriceFor(sizeId, side, qty) {
        var sz = LEAFLET_SIZES.find(function(s){ return s.id === sizeId; });
        if (!sz) sz = LEAFLET_SIZES[0];
        var per = sz.perSheet[side === 'double' ? 'double' : 'single'];
        var disc = _soLeafletQtyDisc(qty);
        return Math.round(per * qty * disc);
    }
    window._soLeafletOptMult = _soLeafletOptMult;
    // 2026-07-04: 낱장 인쇄 실제 사이즈(mm) — leafletSize(규격) 또는 leafletCustomW/H(비규격)가 authoritative.
    //   customSize/customW 는 desync 위험 → 카트표시/주문/작업지시서는 모두 이 함수로 통일.
    //   o 는 state 또는 cart item (둘 다 leafletSize/leafletCustomW/H 보유).
    function _soLeafletDimsMm(o) {
        if (!o) return null;
        if (o.leafletCustomW && o.leafletCustomH) return { w: Math.round(o.leafletCustomW), h: Math.round(o.leafletCustomH) };
        var sz = (typeof LEAFLET_SIZES !== 'undefined') ? LEAFLET_SIZES.find(function(s){ return s.id === o.leafletSize; }) : null;
        if (sz) return { w: sz.wMm, h: sz.hMm };
        return null;
    }
    window._soLeafletDimsMm = _soLeafletDimsMm;
    // 2026-07-04: 낱장 인쇄 — A3(297×420) 초과 사이즈는 디지털 소량인쇄 불가 → 최소 1,000장.
    //   규격 A2 이거나, 비규격 실치수가 A3 를 벗어나면(회전 포함) bulk.
    var LEAFLET_MIN_BULK_QTY = 1000;
    function _soLeafletNeedsBulk() {
        if (state.leafletSize === 'A2') return true;
        if (state.leafletCustomW && state.leafletCustomH) {
            var lo = Math.min(state.leafletCustomW, state.leafletCustomH);
            var hi = Math.max(state.leafletCustomW, state.leafletCustomH);
            if (hi > 420 || lo > 297) return true;
        }
        return false;
    }
    function _soLeafletEnforceMinQty() {
        if (!state.isLeaflet || !_soLeafletNeedsBulk()) return;
        if ((parseInt(state.qty, 10) || 1) < LEAFLET_MIN_BULK_QTY) {
            state.qty = LEAFLET_MIN_BULK_QTY;
            var qi = document.getElementById('soQty');
            if (qi) qi.value = LEAFLET_MIN_BULK_QTY;
        }
    }
    window._soLeafletNeedsBulk = _soLeafletNeedsBulk;
    function _soIsLeafletProduct(p) {
        if (!p) return false;
        var code = (p.code || '').toLowerCase();
        if (code.startsWith('pp_lf')) return true;
        var name = ((p.name_kr || p.name || '') + ' ' + (p.name || '')).toLowerCase();
        return /낱장\s*인쇄|leaflet|flyer/.test(name);
    }
    window._soIsLeafletProduct = _soIsLeafletProduct;
    window.LEAFLET_SIZES = LEAFLET_SIZES;
    window._soLeafletAutoSize = _soLeafletAutoSize;
    window._soLeafletPriceFor = _soLeafletPriceFor;

    // 2026-06-13: 시트지 family — 6종 통합 (관리자 표시 순서)
    //   이전엔 4종 (VINYL) + 2종 (SHEET) 로 별도 시스템 분리되어 있었음. 한 그리드에 6장 노출.
    var VINYL_CODES_ORDERED = [
        '96587-2',         // 1. 떼었다 붙이는 시트지
        '78963',           // 2. 안개시트지
        '456456546546',    // 3. 차량 랩핑시트 라텍스인쇄
        '96587',           // 4. 글씨 커팅시트
        '78965',           // 5. 투명시트지 점착
        '234234243545'     // 6. 투명시트 비점착
    ];
    function _soIsVinylProduct(p) {
        if (!p) return false;
        return VINYL_CODES_ORDERED.indexOf(p.code) >= 0;
    }
    var _soVinylCache = null;
    async function _soLoadVinylVariants(currentCode) {
        var sec = document.getElementById('soVinylVariantsSec');
        var grid = document.getElementById('soVinylVariants');
        if (!sec || !grid) return;
        try {
            if (!_soVinylCache) {
                var sb = getSb(); if (!sb) { sec.style.display = 'none'; return; }
                var _COLS = 'code,name,name_jp,name_us,price,price_jp,price_us,img_url,category,sort_order,width_mm,height_mm';
                var r1 = await sb.from('admin_products').select(_COLS).in('code', VINYL_CODES_ORDERED);
                var rows = (r1 && r1.data) || [];
                var _byCode = {};
                rows.forEach(function(r){ if (r && r.code) _byCode[r.code] = r; });
                _soVinylCache = VINYL_CODES_ORDERED
                    .map(function(c){ return _byCode[c]; })
                    .filter(function(r){ return !!r; });
                console.log('[so] vinyl variants loaded:', _soVinylCache.length);
            }
            if (_soVinylCache.length < 2) { sec.style.display = 'none'; return; }
            var lang = window.__PS_LANG || (window.__SITE_CODE === 'JP' ? 'ja' : window.__SITE_CODE === 'US' ? 'en' : 'ko');
            grid.innerHTML = _soVinylCache.map(function (p) {
                var nm = p.name; if (lang === 'ja' && p.name_jp) nm = p.name_jp; else if (lang !== 'ko' && p.name_us) nm = p.name_us;
                var img = p.img_url || 'https://placehold.co/200?text=Vinyl';
                var safeNm = String(nm || '').replace(/[<>"]/g, '');
                var safeCode = String(p.code || '').replace(/'/g, "\\'");
                var priceVal = p.price || 0;
                var isCur = (p.code === currentCode);
                var borderColor = isCur ? '#7c3aed' : '#e7e5e4';
                var borderW = isCur ? '2.5px' : '1.5px';
                var ring = isCur ? 'box-shadow:0 0 0 3px rgba(124,58,237,0.15);' : '';
                return '<div onclick="window._soSwitchVinyl(\'' + safeCode + '\')" style="cursor:pointer; display:flex; flex-direction:column; border:' + borderW + ' solid ' + borderColor + '; border-radius:10px; overflow:hidden; background:#fff; transition:border-color .15s ease; ' + ring + '">' +
                    '<div style="position:relative; padding-bottom:100%; background:#f8fafc; overflow:hidden;">' +
                        '<img src="' + img + '" loading="lazy" style="position:absolute; inset:0; width:100%; height:100%; object-fit:cover;" onerror="this.style.opacity=0">' +
                        (isCur ? '<div style="position:absolute; top:4px; right:4px; background:#7c3aed; color:#fff; padding:2px 6px; border-radius:4px; font-size:9.5px; font-weight:900;">' + tr('현재','現在','Current') + '</div>' : '') +
                    '</div>' +
                    '<div style="padding:6px 8px;">' +
                        '<div style="font-size:11px; font-weight:700; color:#1e293b; line-height:1.3; height:28px; overflow:hidden;" title="' + safeNm + '">' + safeNm + '</div>' +
                        '<div style="font-size:11px; font-weight:800; color:#dc2626; margin-top:2px;">' + fmtPrice(priceVal) + '</div>' +
                    '</div>' +
                '</div>';
            }).join('');
            sec.style.display = '';
        } catch (e) { console.warn('[so] vinylVariants render', e); sec.style.display = 'none'; }
    }
    window._soLoadVinylVariants = _soLoadVinylVariants;
    window._soIsVinylProduct = _soIsVinylProduct;

    // 2026-06-13: 낱장 인쇄 렌더 — 사이즈/면/용지/박/후가공
    function _soRenderLeafletAll() {
        var sec = document.getElementById('soLeafletPresetSec');
        if (!sec) return;
        // 사이즈 카드
        var szGrid = document.getElementById('soLeafletSizeGrid');
        if (szGrid) {
            szGrid.innerHTML = LEAFLET_SIZES.map(function(sz){
                var sel = (state.leafletSize === sz.id);
                var bc = sel ? '#7c3aed' : '#e2e8f0';
                var bg = sel ? '#faf5ff' : '#fff';
                // 2026-06-14: 1매 기준가 (perSheet) 표시. 양면 선택 시 양면가로 갱신.
                var p1 = sz.perSheet[state.leafletSide === 'double' ? 'double' : 'single'];
                return '<div onclick="window._soPickLeafletSize(\'' + sz.id + '\')" style="cursor:pointer; padding:12px 8px; text-align:center; border:2px solid ' + bc + '; background:' + bg + '; border-radius:12px;">' +
                    '<div style="font-size:15px; font-weight:900; color:#1e293b;">' + sz.label + '</div>' +
                    '<div style="font-size:10.5px; color:#94a3b8; margin-top:3px;">' + sz.wMm + '×' + sz.hMm + 'mm</div>' +
                    '<div style="font-size:12px; font-weight:800; color:#6366f1; margin-top:5px;">' + fmtPrice(p1) + tr(' / 매', ' / 枚', ' / pc') + '</div>' +
                '</div>';
            }).join('');
        }
        // 단/양면 버튼 — 활성 상태
        var bs1 = document.getElementById('soLfSideSingle'), bs2 = document.getElementById('soLfSideDouble');
        if (bs1 && bs2) {
            var dbl = (state.leafletSide === 'double');
            bs1.style.background = dbl ? '#fff' : 'linear-gradient(135deg,#6366f1,#4338ca)';
            bs1.style.color = dbl ? '#475569' : '#fff';
            bs1.style.borderColor = dbl ? '#e7e5e4' : '#4338ca';
            bs2.style.background = dbl ? 'linear-gradient(135deg,#6366f1,#4338ca)' : '#fff';
            bs2.style.color = dbl ? '#fff' : '#475569';
            bs2.style.borderColor = dbl ? '#4338ca' : '#e7e5e4';
        }
        // v722: 리플렛 옵션 카드 — 명함과 동일한 `_bizCard2tone` 스타일 + hover preview + 모바일 모달
        function _renderOptCard(o, selected, onClickStr, category) {
            var nm = _bizI18n(o, 'name');
            var ds = _bizI18n(o, 'desc');
            var priceTag = (o.price > 0) ? '+' + fmtPrice(o.price) : '';
            return '<div class="so-lf-opt-card" data-opt-cat="' + category + '" data-opt-key="' + o.key + '" '
                + 'onmouseenter="window._soOptPreview && window._soOptPreview(this, true)" '
                + 'onmouseleave="window._soOptPreview && window._soOptPreview(this, false)" '
                + 'onclick="window._soBizCardClick(\'' + category + '\',\'' + o.key + '\', function(){' + onClickStr + ';})" '
                + 'style="position:relative; cursor:pointer;">'
                + _bizCard2tone(nm, ds, priceTag, selected)
                + '</div>';
        }
        // 용지 (LEAFLET_PAPERS — 일반지 스노우180/아트180 + 고급지)
        var ppGrid = document.getElementById('soLfPaperGrid');
        if (ppGrid && typeof LEAFLET_PAPERS !== 'undefined') {
            ppGrid.innerHTML = LEAFLET_PAPERS.map(function(o){
                return _renderOptCard(o, state.leafletPaper === o.key, "window._soPickLeafletPaper('" + o.key + "')", 'paper');
            }).join('');
        }
        // v722: 박 (BIZ_FOILS) — 없음 카드 제거. 선택된 박 다시 클릭하면 해제 (명함과 동일)
        var foGrid = document.getElementById('soLfFoilGrid');
        if (foGrid && typeof BIZ_FOILS !== 'undefined') {
            foGrid.innerHTML = BIZ_FOILS.map(function(o){
                return _renderOptCard(o, state.leafletFoil === o.key, "window._soPickLeafletFoil('" + o.key + "')", 'foil');
            }).join('');
        }
        // 후가공 (BIZ_FINISHES) — 체크박스 다중 선택
        var fnGrid = document.getElementById('soLfFinishGrid');
        if (fnGrid && typeof LEAFLET_FINISHES !== 'undefined') {
            fnGrid.innerHTML = LEAFLET_FINISHES.map(function(o){
                var sel = !!(state.leafletFinishes && state.leafletFinishes[o.key]);
                return _renderOptCard(o, sel, "window._soToggleLeafletFinish('" + o.key + "')", 'finish');
            }).join('');
        }
        // v710/v722: 토글 버튼 라벨에 현재 선택값 표시 (✓ 표시 — 미선택 시 빈 문자열)
        try {
            var pCur = document.getElementById('soLfPaperCurrent');
            if (pCur && typeof LEAFLET_PAPERS !== 'undefined') {
                var pSel = LEAFLET_PAPERS.find(function(o){ return o.key === state.leafletPaper; });
                pCur.textContent = pSel ? _bizI18n(pSel, 'name') : '-';
            }
            var fCur = document.getElementById('soLfFoilCurrent');
            if (fCur) {
                if (state.leafletFoil && typeof BIZ_FOILS !== 'undefined') {
                    var fSel = BIZ_FOILS.find(function(o){ return o.key === state.leafletFoil; });
                    fCur.textContent = fSel ? '· ✓ ' + _bizI18n(fSel, 'name') : '';
                } else {
                    fCur.textContent = '';
                }
            }
            var fnCur = document.getElementById('soLfFinishCurrent');
            if (fnCur) {
                var picked = state.leafletFinishes ? Object.keys(state.leafletFinishes).filter(function(k){ return !!state.leafletFinishes[k]; }) : [];
                if (picked.length > 0 && typeof LEAFLET_FINISHES !== 'undefined') {
                    var names = picked.map(function(k){
                        var o = LEAFLET_FINISHES.find(function(x){ return x.key === k; });
                        return o ? _bizI18n(o, 'name') : k;
                    });
                    fnCur.textContent = '· ✓ ' + names.join(', ');
                } else {
                    fnCur.textContent = '';
                }
            }
        } catch(_lbE){}
        // 2026-07-04: A3 초과(A2 등·비규격) → 최소 1,000장 안내 토글 + 소량 안내 숨김.
        try {
            var _lfBulk = _soLeafletNeedsBulk();
            var _bulkEl = document.getElementById('soLfBulkNotice');
            var _minOneEl = document.getElementById('soLfMinOneNotice');
            if (_bulkEl) _bulkEl.style.display = _lfBulk ? '' : 'none';
            if (_minOneEl) _minOneEl.style.display = _lfBulk ? 'none' : '';
        } catch(_bkE){}
    }
    // 2026-07-01: 책자제본 (435345435) — 사이즈 + 표지/내지 용지 + 페이지수 × 권수. 박/후가공은 하단 soCp 공용 사용.
    var BOOKLET_CODE = '435345435';
    var BOOKLET_INNER_PAPERS = [
        { key:'mojo70',   name_kr:'모조지 70g',   name_jp:'上質紙 70g',     name_us:'Woodfree 70g' },
        { key:'snow90',   name_kr:'스노우지 90g', name_jp:'スノー紙 90g',   name_us:'Snow 90g' },
        { key:'art90',    name_kr:'아트지 90g',   name_jp:'アート紙 90g',   name_us:'Art 90g' },
        { key:'rendez90', name_kr:'랑데뷰 90g',   name_jp:'ランデブー 90g', name_us:'Rendezvous 90g' }
    ];
    function _soIsBookletProduct(p) { return !!(p && String(p.code || '') === BOOKLET_CODE); }
    function _soRenderBookletAll() {
        if (typeof BIZ_PAPERS === 'undefined') return;
        var _opt = function(o, selKey){ return '<option value="' + o.key + '"' + (o.key === selKey ? ' selected' : '') + '>' + _bizI18n(o, 'name') + '</option>'; };
        var cp = document.getElementById('soBkCoverPaper');
        if (cp) cp.innerHTML = BIZ_PAPERS.map(function(o){ return _opt(o, state.bookletCoverPaper); }).join('');
        var ip = document.getElementById('soBkInnerPaper');
        if (ip) ip.innerHTML = BOOKLET_INNER_PAPERS.map(function(o){ return _opt(o, state.bookletInnerPaper); }).join('');
        try {
            document.querySelectorAll('#soBkSizeGrid .so-bk-size').forEach(function(b){
                var on = (b.getAttribute('data-bk-size') === state.bookletSize);
                b.style.borderColor = on ? '#4338ca' : '#e5e7eb';
                b.style.background = on ? '#eef2ff' : '#fff';
                b.style.color = on ? '#3730a3' : '#334155';
            });
        } catch (e) {}
        _soBkUpdateThickness();
    }
    window._soRenderBookletAll = _soRenderBookletAll;
    function _soBkUpdateThickness() {
        var el = document.getElementById('soBkThickness');
        if (!el) return;
        var pages = Math.max(1, parseInt(state.bookletPages, 10) || 1);
        var mm = pages * 0.08;   // 100페이지 ≈ 8mm
        el.textContent = '≈ ' + (mm < 10 ? mm.toFixed(1) : Math.round(mm)) + ' mm';
    }
    window._soBkSet = function(field, val) {
        if (field === 'pages') state.bookletPages = Math.max(1, Math.min(500, parseInt(val, 10) || 1));
        else if (field === 'coverPaper') state.bookletCoverPaper = val;
        else if (field === 'innerPaper') state.bookletInnerPaper = val;
        if (field === 'pages') _soBkUpdateThickness();
        if (typeof recalc === 'function') recalc();
    };
    window._soBkPickSize = function(name, w, h) {
        state.bookletSize = name; state.bookletW = w; state.bookletH = h;
        var wi = document.getElementById('soBkW'), hi = document.getElementById('soBkH');
        if (wi) wi.value = ''; if (hi) hi.value = '';
        _soRenderBookletAll();
        if (typeof recalc === 'function') recalc();
    };
    window._soBkCustomSize = function() {
        var wi = document.getElementById('soBkW'), hi = document.getElementById('soBkH');
        var w = parseInt(wi && wi.value, 10) || 0, h = parseInt(hi && hi.value, 10) || 0;
        if (w > 0 && h > 0) { state.bookletSize = 'custom'; state.bookletW = w; state.bookletH = h; }
        _soRenderBookletAll();
        if (typeof recalc === 'function') recalc();
    };
    // 책자 총액: (1000 + 페이지×100) × 권수 (+ 박/후가공은 인자로 주면 가산 — 카트용). recalc 는 addonTotal 로 cp 박 처리.
    // 2026-07-02: 책자 가격 = min(디지털 소량가, 옵셋 대량가). 박/후가공(opt)은 정액 별도 가산.
    //   ● 디지털(소량): 표지 1,000 + 내지(페이지×100), 부수 정비례 → 1부부터 저렴 (소량 특화 유지).
    //   ● 옵셋(대량): 성원애드피아 결제액(VAT포함) 선형근사 × 0.93 (약 7% 저렴).
    //       성원 선형근사: 고정 = 8,004×p + 239,168 / 부당 = 174.4 + 28.02×p  (p=내지 페이지수).
    //   두 방식 중 저렴한 쪽 자동 채택 → 소량은 디지털(성원보다 훨씬 저렴), 대량은 옵셋(성원보다 ~7% 저렴).
    //   교차점 ~150~200부. 둘 다 증가함수라 수량 늘수록 가격도 오름(역전 없음).
    //   검증(우리/성원): 32P 1000부 1,456,692/1,566,400(-7%) · 8P 4000부 1,764,619/1,897,500(-7%).
    function _soBookletPrintCost(pages, qty) {
        pages = Math.max(1, parseInt(pages, 10) || 1);
        qty = Math.max(1, parseInt(qty, 10) || 1);
        var digital = (1000 + pages * 100) * qty;
        var offset = Math.round(((8004 * pages + 239168) + (174.4 + 28.02 * pages) * qty) * 0.93);
        return Math.min(digital, offset);
    }
    window._soBookletPrintCost = _soBookletPrintCost;
    function _soBookletTotal(pages, qty, foilKey, finishes) {
        pages = Math.max(1, parseInt(pages, 10) || 1);
        qty = Math.max(1, parseInt(qty, 10) || 1);
        var opt = 0;
        if (foilKey && typeof BIZ_FOILS !== 'undefined') { var f = BIZ_FOILS.find(function(o){ return o.key === foilKey; }); if (f) opt += (f.price || 0); }
        if (finishes && typeof BIZ_FINISHES !== 'undefined') Object.keys(finishes).forEach(function(k){ if (finishes[k]) { var x = BIZ_FINISHES.find(function(o){ return o.key === k; }); if (x) opt += (x.price || 0); } });
        return _soBookletPrintCost(pages, qty) + opt;
    }

    window._soPickLeafletSize = function(id) {
        state.leafletSize = id;
        // 규격 선택 시 비규격 치수 초기화 (stale 치수가 bulk 판정 오염 방지)
        state.leafletCustomW = null;
        state.leafletCustomH = null;
        var sz = LEAFLET_SIZES.find(function(s){ return s.id === id; });
        if (sz) { state.customW = sz.wMm / 10; state.customH = sz.hMm / 10; }
        // 2026-07-04: A3 초과(A2)면 최소 1,000장 자동 보정
        _soLeafletEnforceMinQty();
        _soRenderLeafletAll();
        if (typeof recalc === 'function') recalc();
    };
    window._soPickLeafletSide = function(side) {
        state.leafletSide = (side === 'double') ? 'double' : 'single';
        _soRenderLeafletAll();
        if (typeof recalc === 'function') recalc();
    };
    window._soPickLeafletPaper = function(key) {
        state.leafletPaper = key;
        _soRenderLeafletAll();
        if (typeof recalc === 'function') recalc();
    };
    window._soPickLeafletFoil = function(key) {
        // v722: 같은 박 다시 클릭 시 해제 (명함과 동일 토글 UX)
        state.leafletFoil = (state.leafletFoil === key) ? null : key;
        _soRenderLeafletAll();
        if (typeof recalc === 'function') recalc();
    };
    window._soToggleLeafletFinish = function(key) {
        if (!state.leafletFinishes) state.leafletFinishes = {};
        state.leafletFinishes[key] = !state.leafletFinishes[key];
        _soRenderLeafletAll();
        if (typeof recalc === 'function') recalc();
    };
