    function _optHint(vis) {
        if (!vis) return '';
        var lg = (typeof getLang === 'function') ? getLang() : 'ko';
        if (lg === 'ja') return vis.hint_jp || vis.hint_kr || '';
        if (lg === 'en') return vis.hint_us || vis.hint_kr || '';
        return vis.hint_kr || '';
    }
    // 2026-06-23 v713: 모바일/PC 클릭 라우터 — 모바일은 모달, PC 는 선택만
    window._soOptCardClick = function(cardEl, doSelect) {
        var isTouch = window.matchMedia && window.matchMedia('(pointer:coarse)').matches;
        if (isTouch) {
            var cat = cardEl.getAttribute('data-opt-cat');
            var key = cardEl.getAttribute('data-opt-key');
            window._soShowOptInfo(cat, key, doSelect);
        } else {
            if (typeof doSelect === 'function') doSelect();
        }
    };
    // v719: 명함 카드용 (cat/key 직접 전달) — 모바일은 모달, PC 는 즉시 선택
    window._soBizCardClick = function(cat, key, doSelect) {
        // 2026-06-25: PC/모바일 모두 전체화면 미리보기 모달로 통일.
        //   (작은 호버 미리보기 박스가 카드를 가려 불편 → 클릭하면 전체화면으로 보고 선택/닫기)
        window._soShowOptInfo(cat, key, doSelect);
    };
