        var fxOpen = !!state._cpFinishOpen;
        // 박 토글 + 그리드
        var fw = document.getElementById('soCpFoilWrap');
        var fa = document.getElementById('soCpFoilChevron');
        var fc = document.getElementById('soCpFoilCurrent');
