    // 2026-07-14: 스티커 가격 — 기준 사이즈 100×100mm(면적 1.0) 낱장단가 × 면적비례 × 수량.
    //   일반(강접까지 4종): 낱장 10원 정액 → 500매 5천 / 1000매 1만 / 2000매 2만.
    //   특수(나머지): 수량 앵커 (10매 3만 / 50매 5만 / 100매 8만 / 500매 15만 / 1000매 20만).
    //   면적 비례: 실제(W×H)/10000 을 낱장단가에 곱 (200×100mm → 2배). + 모양(재단) 정액.
    //   팬시: basePrice/4 (기존 유지). stState = { productCode, w, h, qty, type, shape, isFancy }.
    function _stickerCalcPrice(stState) {
        if (!stState) return 0;
        // variant 캐시에서 찾음 — 모달 진입 시 _soLoadStickerVariants 가 미리 채워둠.
        var variants = _stickerVariantsCache || [];
        var v = stState.productCode ? variants.find(function(x){ return x.code === stState.productCode; }) : null;
        if (!v) return 0;
        var basePrice = Number(v.price) || 0;
        var qty = Math.max(1, Number(stState.qty) || 1000);
        // 낱장(개당) 단가를 먼저 반올림 후 × 수량 — 제품페이지 '단가 × 수량' 표기와 카트 합계 완전 일치.
        var perUnit;
        if (stState.isFancy) {
            // 팬시는 4매 단위 판매 → 개당 = 기준가/4. 2026-07-14: 종류(용지) 배수 적용 — 기본 4종 1× / 특수 3×.
            perUnit = (basePrice / 4) * (_stickerIsBaseType(stState.type) ? 1 : 3);
        } else {
            var w = Math.max(10, Number(stState.w) || 100);
            var h = Math.max(10, Number(stState.h) || 100);
            // 2026-07-14: 면적 배수 하한 1.0 — 100×100mm 이하(40×40 등)는 100×100 가격과 동일(더 싸지지 않음).
            //   100×100 초과만 면적 비례로 증가. (예: 200×100 → 2.0배)
            var area = Math.max(1.0, (w * h) / 10000);
            perUnit = _stickerPerUnitRef(stState.type, qty) * area;
        }
        var subtotal = Math.round(perUnit) * qty;
        // 2026-07-14: 모양(재단) 정액 — 사각 0 / 간단도형 +10,000 / 복잡모양 +30,000. (구 dieCut 토글 호환: dieCut=true → complex)
        var shapeFee = _stickerShapeFee(stState.shape, stState.dieCut);
        return subtotal + shapeFee;
    }
    // 일반(기본가) 종류 4종 — 강접까지. 나머지는 특수(고가).
    var STICKER_BASE_TYPES = ['art_matte', 'matte', 'gloss', 'strong'];
    function _stickerIsBaseType(typeKey) { return STICKER_BASE_TYPES.indexOf(typeKey || 'art_matte') >= 0; }
    // 기준 사이즈(100×100mm) 낱장 단가(원). 사이즈는 면적 비례로 별도 곱함.
    function _stickerPerUnitRef(typeKey, qty) {
        qty = Math.max(1, Number(qty) || 1000);
        // 일반(기본가): 수량 앵커 낱장단가 — 100매 4천(40원)/500매 5천(10원)/1000매 8천(8원)/2000매 1만(5원). 2026-07-14.
        // 특수용지: 10매3만(3000) / 50매5만(1000) / 100매8만(800) / 500매15만(300) / 1000매20만(200).
        var A = _stickerIsBaseType(typeKey)
            ? [[100,40],[500,10],[1000,8],[2000,5]]
            : [[10,3000],[50,1000],[100,800],[500,300],[1000,200]];
        if (qty <= A[0][0]) return A[0][1];
        if (qty >= A[A.length-1][0]) return A[A.length-1][1];
        for (var i = 0; i < A.length - 1; i++) {
            if (qty >= A[i][0] && qty <= A[i+1][0]) {
                var t = (qty - A[i][0]) / (A[i+1][0] - A[i][0]);
                return A[i][1] + t * (A[i+1][1] - A[i][1]);
            }
        }
        return A[A.length-1][1];
    }
    // 모양(재단) 정액. shape: 'square'|'simple'|'complex'. (구 dieCut boolean → complex 로 매핑)
    function _stickerShapeFee(shape, legacyDieCut) {
        if (!shape) shape = legacyDieCut ? 'complex' : 'square';
        if (shape === 'simple') return 10000;   // (구 간단도형 — UI 삭제됨, 호환용)
        if (shape === 'complex') return 10000;   // 2026-07-14: 모양스티커 — 3만→1만원
        return 0;
    }
    // 2026-07-14: 간단도형 9종 (간단도형 선택 시 편집기 칼선 생성용). key = 편집기 _meCutlineShapeItem(kind) 와 공유.
    var STICKER_SHAPE_KINDS = [
        { key:'roundedCorner', name_kr:'귀돌이', name_jp:'角丸',   name_us:'Rounded' },
        { key:'circle',        name_kr:'원형',   name_jp:'円形',   name_us:'Circle' },
        { key:'ellipse',       name_kr:'타원형', name_jp:'楕円',   name_us:'Ellipse' },
        { key:'penta',         name_kr:'5각형',  name_jp:'五角形', name_us:'Pentagon' },
        { key:'hexa',          name_kr:'6각형',  name_jp:'六角形', name_us:'Hexagon' },
        { key:'octa',          name_kr:'8각형',  name_jp:'八角形', name_us:'Octagon' },
        { key:'rhombus',       name_kr:'마름모', name_jp:'ひし形', name_us:'Rhombus' },
        { key:'tri',           name_kr:'세모',   name_jp:'三角形', name_us:'Triangle' },
        { key:'star',          name_kr:'별',     name_jp:'星',     name_us:'Star' }
    ];
    // 도형별 정규화 점 [0..1] 생성기 — SVG 미리보기와 편집기 칼선(_meCutlineShapeItem) 이 동일 함수 사용.
    window._stickerShapePts = function(kind) {
        var TAU = Math.PI * 2, pts = [], i, a;
        function poly(n, rot){ var o = []; for (i = 0; i < n; i++){ a = -Math.PI/2 + rot + TAU * i / n; o.push({ x:0.5 + 0.5*Math.cos(a), y:0.5 + 0.5*Math.sin(a) }); } return o; }
        switch (kind) {
            case 'circle':  { for (i = 0; i < 48; i++){ a = TAU*i/48; pts.push({ x:0.5 + 0.5*Math.cos(a), y:0.5 + 0.5*Math.sin(a) }); } break; }
            case 'ellipse': { for (i = 0; i < 48; i++){ a = TAU*i/48; pts.push({ x:0.5 + 0.5*Math.cos(a), y:0.5 + 0.35*Math.sin(a) }); } break; }
            case 'roundedCorner': {
                var r = 0.2;
                var corners = [[1-r,r,-Math.PI/2,0],[1-r,1-r,0,Math.PI/2],[r,1-r,Math.PI/2,Math.PI],[r,r,Math.PI,Math.PI*1.5]];
                corners.forEach(function(c){ for (var k = 0; k <= 6; k++){ var aa = c[2] + (c[3]-c[2])*k/6; pts.push({ x:c[0] + r*Math.cos(aa), y:c[1] + r*Math.sin(aa) }); } });
                break;
            }
            case 'penta': pts = poly(5, 0); break;
            case 'hexa':  pts = poly(6, Math.PI/6); break;
            case 'octa':  pts = poly(8, Math.PI/8); break;
            case 'rhombus': pts = [{x:.5,y:0},{x:1,y:.5},{x:.5,y:1},{x:0,y:.5}]; break;
            case 'tri':     pts = [{x:.5,y:0},{x:1,y:1},{x:0,y:1}]; break;
            case 'star':    { for (i = 0; i < 10; i++){ a = -Math.PI/2 + Math.PI*i/5; var rr = (i%2===0) ? 0.5 : 0.22; pts.push({ x:0.5 + rr*Math.cos(a), y:0.5 + rr*Math.sin(a) }); } break; }
            default: pts = [{x:0,y:0},{x:1,y:0},{x:1,y:1},{x:0,y:1}];
        }
        return pts;
    };
    function _stickerShapeSvg(kind, stroke) {
        var pts = window._stickerShapePts(kind), S = 30, pad = 3, sz = S - pad*2;
        var d = pts.map(function(p, i){ return (i ? 'L' : 'M') + (pad + p.x*sz).toFixed(1) + ' ' + (pad + p.y*sz).toFixed(1); }).join(' ') + ' Z';
        return '<svg width="30" height="30" viewBox="0 0 30 30" fill="none" style="display:block; margin:0 auto;">'
             + '<path d="' + d + '" stroke="' + stroke + '" stroke-width="1.6" stroke-linejoin="round"/></svg>';
    }

    // 2026-05-13: 사이즈 입력 → 면적 × 단가 (m²) 자동 계산 상품 — 현수막·실사출력 등
    // admin_products.is_custom_size = true 이면서 가벽/박스/자유인쇄커팅 처럼 자체 UI가 없는 상품
    function _soIsCustomSizeProduct(p) {
        if (!p) return false;
        // 가벽·박스·자유인쇄커팅 은 별도 사이즈 UI 사용
        if (_soIsWallProduct(p)) return false;
        if (_soIsBoxProduct(p)) return false;
        if (_soIsCutPrintProduct(p)) return false;
        // is_custom_size 또는 width_mm/height_mm 있고 name 에 현수막/배너/실사출력
        if (p.is_custom_size === true) return true;
        const name = ((p.name || '') + ' ' + (p.name_us || '') + ' ' + (p.name_kr || '')).toLowerCase();
        if (/현수막|배너|실사\s*출력|시트지|광고\s*인쇄|banner|hyunsumak/i.test(name)) return true;
        // 2026-05-14: 아크릴 굿즈 (키링·코롯도·키홀더 등) — 소형이지만 cm² 단가 계산
        if (_soIsAcrylicGoodsProduct(p)) return true;
        return false;
    }

    // 2026-05-14: 아크릴 굿즈 감지 (키링·코롯도·아크릴 굿즈 등)
    // - code prefix: gds_acr / gds_kr / acr_kr
    // - 이름: 키링/코롯도/아크릴 키홀더/keyring/korotto
    // 이런 제품은 5cm×5cm 같은 소형 사이즈가 정상 → min 1cm 허용 + 고리/부자재 자동 표시
    function _soIsAcrylicGoodsProduct(p) {
        if (!p) return false;
        const code = (p.code || '').toLowerCase();
        const cat = (p.category || '').toLowerCase();
        const name = ((p.name || '') + ' ' + (p.name_us || '') + ' ' + (p.name_kr || '')).toLowerCase();
        if (/^gds_acr|^gds_kr|^acr_kr|^acr_g/.test(code)) return true;
        if (/^(gds_acr|acrylic_goods|acrylic|굿즈|goods)$/.test(cat)) return true;
        if (/아크릴\s*키링|아크릴\s*키홀더|아크릴\s*굿즈|아크릴\s*스탠드|코롯도|korotto|acrylic\s*(keyring|charm|stand|goods|holder|tag)/i.test(name)) return true;
        return false;
    }

    // 2026-05-13: 포맥스/폼보드 감지 (대형택배 3만원)
    function _soIsForexFoamProduct(p) {
        if (!p) return false;
        const name = ((p.name || '') + ' ' + (p.name_us || '') + ' ' + (p.name_kr || '')).toLowerCase();
        return /포맥스|폼보드|forex|foam\s*board|pvc\s*foam/i.test(name);
    }

    // 2026-05-13: 일반 인쇄물 감지 (광고/상업/홈/굿즈/기타) — 허니콤·포맥스·폼보드 제외 모든 상품
    // 패브릭은 자체 designer, 종이매대는 자체 페이지라 simple_order 에 들어오지 않음
    function _soIsGeneralPrintProduct(p) {
        if (!p) return false;
        if (_soIsHoneycombProduct(p)) return false;
        if (_soIsForexFoamProduct(p)) return false;
        return true;
    }

    // 2026-05-13: 택배배송 가능 상품 — 허니콤보드배너(hb_bn_*) + 인스타판넬(hb_insta / lll0 / 0ll / lllllp / ppp)
    // 택배 1박스에 2장 묶음 가능 → 가격 = ceil(qty/2) × 30,000원
    function _soIsParcelShipProduct(p) {
        if (!p) return false;
        const code = (p.code || '').toLowerCase();
        const cat = (p.category || '').toLowerCase();
        const name = ((p.name || '') + ' ' + (p.name_us || '')).toLowerCase();
        if (code.startsWith('hb_bn')) return true;        // 허니콤배너 단/양면/연결형
        if (cat === 'hb_insta' || cat.indexOf('insta') >= 0) return true;
        if (['lll0', '0ll', 'lllllp', 'ppp'].indexOf(code) >= 0) return true;
        if (/배너|banner|인스타\s*판넬|instagram\s*panel|photo\s*booth/i.test(name)) return true;
        return false;
    }

