        //   isBanner=false 인 hb_bn_2(연결형) 같은 코드에서도 종류 카드가 보이도록 isBanner 조건 밖으로 이동.
        state.isBannerFamily = !!(p && p.code && /^hb_bn/i.test(p.code));
