                // 2026-06-13: 카트 항목별 비용 breakdown — 단가/받침대/옵션/배송/칼선작업/합계
                //   여러 상품이 있으면 첫 번째 (가장 큰 배송비) 만 배송비 표시, 나머지는 묶음배송 표시
                var _bd = [];
                var _bdQty = item.qty || 1;
